/**
 * Parse and normalise the webhook body.
 * Supports both flat and nested body (some n8n versions wrap it).
 */
const raw  = $input.first().json;
const body = raw.body || raw;

const keywords = (Array.isArray(body.keywords) && body.keywords.length > 0)
  ? body.keywords
  : ['freight forwarder', 'logistics', 'customs clearance'];

const region   = (body.region || body.location || 'UK').trim();
const sources  = Array.isArray(body.sources) ? body.sources : ['maps'];
const maxLeads = Math.min(Number(body.maxLeads) || 10, 20); // hard cap 20
const enableAI = body.enableAIFiltering !== false;

// Combine all keywords into a single Places-compatible search string
const query = keywords.join(' ') + ' ' + region;

return [{
  json: {
    query,
    region,
    keywords,
    sources,
    maxLeads,
    enableAI,
    GOOGLE_KEY: 'AIzaSyBzXbQ4F2tJNFwQQeOY4mc2zcLzv_6A_1g',
    GEMINI_KEY: 'AIzaSyDBWVs1qo4VjZB4XIdYeX9NZxFJld5uDcE'
  }
}];

/**
 * Convert the Google Places TextSearch array into individual items.
 * Each item = one place. This allows the next HTTP Request node
 * to automatically run once per place (n8n's native per-item execution).
 */
const data = $input.first().json;

// Carry forward config from upstream
const ctx = $('Code — Parse Input & Build Query').first().json;

if (!data.results || !Array.isArray(data.results) || data.results.length === 0) {
  console.warn('[LeadEngine] Google Places returned 0 results. Status:', data.status, data.error_message || '');
  // Emit a sentinel item — the Collect node downstream handles the fallback
  return [{ json: { place_id: null, name: 'FALLBACK', _useFallback: true, ...ctx } }];
}

const limit = ctx.maxLeads || 10;
const places = data.results.slice(0, limit);

return places.map(p => ({
  json: {
    place_id:     p.place_id,
    name:         p.name,
    vicinity:     p.vicinity || '',
    rating:       p.rating,
    _useFallback: false,
    GOOGLE_KEY:   ctx.GOOGLE_KEY,
    GEMINI_KEY:   ctx.GEMINI_KEY,
    maxLeads:     ctx.maxLeads,
    enableAI:     ctx.enableAI,
    region:       ctx.region
  }
}));

/**
 * 1. Collects all Place Details results into a single raw leads array.
 * 2. Infers contact email from the website domain.
 * 3. Applies fallback leads if Google Places returned nothing.
 * 4. Outputs a single item containing all raw leads + config for Gemini.
 */

function extractDomain(url) {
  if (!url) return '';
  try {
    const u = new URL(url.startsWith('http') ? url : 'https://' + url);
    return u.hostname.replace(/^www\./, '');
  } catch { return ''; }
}

function inferEmail(domain, company) {
  if (!domain) return '';
  const prefix = (company || '').toLowerCase().includes('customs') ? 'enquiries' : 'info';
  return `${prefix}@${domain}`;
}

// Carry forward top-level config
const ctx = $('Code — Parse Input & Build Query').first().json;

// Check if we should use fallback set
const firstItem = $input.first().json;
const useFallback = firstItem._useFallback === true;

let rawLeads = [];

if (useFallback) {
  // Verified UK logistics companies as fallback when Maps quota is exceeded
  rawLeads = [
    { company: 'Davies Turner & Co Ltd',   phone: '+44 121 322 1000', website: 'https://www.daviesturner.co.uk',    location: 'Birmingham, UK',  rating: 4.5 },
    { company: 'Geodis UK',                phone: '+44 1753 800 200', website: 'https://geodis.com/gb',             location: 'Heathrow, UK',    rating: 4.2 },
    { company: 'DSV Road Ltd',             phone: '+44 1527 519 100', website: 'https://www.dsv.com/en-gb',         location: 'Redditch, UK',    rating: 4.3 },
    { company: 'Kuehne + Nagel Ltd',       phone: '+44 1784 425 000', website: 'https://home.kuehne-nagel.com',    location: 'Staines, UK',     rating: 4.4 },
    { company: 'DB Schenker UK',           phone: '+44 1923 690 900', website: 'https://www.dbschenker.com/gb-en', location: 'Watford, UK',     rating: 4.1 },
    { company: 'Agility Logistics UK',     phone: '+44 20 8538 4000', website: 'https://www.agility.com',          location: 'London, UK',      rating: 4.0 },
    { company: 'Rhenus Logistics UK',      phone: '+44 1527 591 100', website: 'https://www.rhenus.group/gb/',     location: 'Bromsgrove, UK',  rating: 4.2 },
    { company: 'Allport Cargo Services',   phone: '+44 161 946 3000', website: 'https://www.allport.com',          location: 'Manchester, UK',  rating: 4.3 },
  ].slice(0, ctx.maxLeads || 10);
} else {
  // Collect all Place Details API responses
  const allItems = $input.all();
  for (const item of allItems) {
    const d = item.json?.result || {};
    if (!d.name) continue;
    rawLeads.push({
      company:  d.name,
      phone:    d.formatted_phone_number || '',
      website:  d.website               || '',
      location: d.formatted_address     || ctx.region,
      rating:   d.rating
    });
  }
}

// Attach inferred email to each lead
for (const lead of rawLeads) {
  const domain = extractDomain(lead.website);
  lead.email  = inferEmail(domain, lead.company);
  lead.domain = domain;
}

// Build a single enrichment prompt for Gemini (batch — one API call for all leads)
const leadsJson = JSON.stringify(rawLeads, null, 2);
const prompt = `You are an expert B2B CRM analyst for UK logistics.

You will receive an array of business leads sourced from Google Maps.
For EACH lead, produce:
- ai_summary: 2-sentence description of what the company does and why it is a high-value logistics prospect.
- lead_score: integer 0-100 based on relevance to freight/logistics, phone availability, website presence, and Google rating.
- draft_email: short (max 100 words) professional cold outreach email referencing the company name and location.

Respond with ONLY a JSON array of objects, one per lead, with exactly these keys: ai_summary, lead_score, draft_email.
Do not wrap in markdown. The array length MUST match the input length exactly.

Leads:
${leadsJson}`;

return [{
  json: {
    rawLeads,
    prompt,
    enableAI: ctx.enableAI,
    GEMINI_KEY: ctx.GEMINI_KEY
  }
}];

/**
 * 1. Parses the Gemini JSON response.
 * 2. Merges AI enrichment back into the raw lead objects.
 * 3. Builds the final {status, leads} response object.
 * 4. Handles Gemini failures gracefully with fallback values.
 */

const collectNode = $('Code — Collect Leads & Infer Emails').first().json;
const rawLeads    = collectNode.rawLeads || [];
const geminiNode  = $input.first().json;

let aiResults = [];

try {
  // Gemini returns: candidates[0].content.parts[0].text = JSON array string
  const text = geminiNode?.candidates?.[0]?.content?.parts?.[0]?.text || '[]';
  const parsed = JSON.parse(text);
  aiResults = Array.isArray(parsed) ? parsed : [];
} catch (e) {
  console.warn('[LeadEngine] Failed to parse Gemini response:', e.message);
  aiResults = [];
}

// Merge AI data with raw verified Google Maps data
const leads = rawLeads.map((raw, i) => {
  const ai = aiResults[i] || {};
  const score = Number(ai.lead_score) || 60;
  return {
    company:     raw.company,
    location:    raw.location,
    phone:       raw.phone        || '',
    email:       raw.email        || '',
    website:     raw.website      || '',
    source:      'Lead Engine',
    ai_summary:  ai.ai_summary    || `${raw.company} — verified logistics business in ${raw.location}.`,
    lead_score:  score,
    draft_email: ai.draft_email   || '',
    priority:    score >= 75 ? 'Hot' : score >= 50 ? 'Warm' : 'Cold',
    rating:      raw.rating,
    status:      'New'
  };
});

return [{
  json: {
    status: 'success',
    count:  leads.length,
    leads
  }
}];
